import { Controller } from '@nestjs/common';
import {
  AccessService,
  CreateAccessRequest,
  CreateAccessResponse,
  DeleteAccessRequest,
  DeleteAccessResponse,
  FindAccessRequest,
  FindAccessResponse,
  HasRightsRequest,
  HasRightsResponse,
  ReadAccessRequest,
  ReadAccessResponse,
} from '@ultimatebackend/proto-schema/access';
import { CommandBus, QueryBus } from '@nestjs/cqrs';
import {
  CreateAccessCommand,
  DeleteAccessCommand,
  FindAccessQuery,
  HasRightsQuery,
  ReadAccessQuery,
} from './cqrs';
import { getIdentityFromCtx } from '@ultimatebackend/core';
import { GrpcMethod } from '@nestjs/microservices';

@Controller('webhook')
export class AccessTokenController implements AccessService<any> {
  constructor(
    private readonly commandBus: CommandBus,
    private readonly queryBus: QueryBus,
  ) {}

  @GrpcMethod('AccessService')
  async createAccess(
    request: CreateAccessRequest,
    ctx: any,
  ): Promise<CreateAccessResponse> {
    const { user, tenantInfo } = getIdentityFromCtx(ctx);
    return await this.commandBus.execute(
      new CreateAccessCommand(
        {
          ...request,
          tenantId: request.tenantId ?? tenantInfo.tenantId,
        },
        user,
      ),
    );
  }

  @GrpcMethod('AccessService')
  async deleteAccess(
    request: DeleteAccessRequest,
    ctx: any,
  ): Promise<DeleteAccessResponse> {
    const { tenantInfo } = getIdentityFromCtx(ctx);
    return await this.commandBus.execute(
      new DeleteAccessCommand(request, request.tenantId ?? tenantInfo.tenantId),
    );
  }

  @GrpcMethod('AccessService')
  async findAccess(
    request: FindAccessRequest,
    ctx: any,
  ): Promise<FindAccessResponse> {
    const { tenantInfo } = getIdentityFromCtx(ctx);
    return await this.queryBus.execute(
      new FindAccessQuery({
        filter: request?.filter,
        tenantId: request?.tenantId ?? tenantInfo.tenantId,
      }),
    );
  }

  @GrpcMethod('AccessService')
  async hasRights(
    request: HasRightsRequest,
    ctx: any,
  ): Promise<HasRightsResponse> {
    return await this.queryBus.execute(new HasRightsQuery(request));
  }

  @GrpcMethod('AccessService')
  async readAccess(
    request: ReadAccessRequest,
    ctx: any,
  ): Promise<ReadAccessResponse> {
    const { tenantInfo } = getIdentityFromCtx(ctx);
    return await this.queryBus.execute(
      new ReadAccessQuery({
        id: request.id,
        tenantId: request.tenantId ?? tenantInfo.tenantId,
      }),
    );
  }
}

import {
  Body,
  Controller,
  Get,
  HttpCode,
  HttpStatus,
  Post,
  UploadedFile,
  Version,
} from '@nestjs/common';
import { ApiOkResponse, ApiTags } from '@nestjs/swagger';

import { RoleType } from '../../constants/role-type.ts';
import { AuthUser } from '../../decorators/auth-user.decorator.ts';
import { Auth } from '../../decorators/http.decorators.ts';
import { ApiFile } from '../../decorators/swagger.schema.ts';
import type { IFile } from '../../interfaces/IFile.ts';
import type { Reference } from '../../types.ts';
import { UserDto } from '../user/dtos/user.dto.ts';
import type { UserEntity } from '../user/user.entity.ts';
import { UserService } from '../user/user.service.ts';
import { AuthService } from './auth.service.ts';
import { LoginPayloadDto } from './dto/login-payload.dto.ts';
import type { UserLoginDto } from './dto/user-login.dto.ts';
import type { UserRegisterDto } from './dto/user-register.dto.ts';

@Controller('auth')
@ApiTags('auth')
export class AuthController {
  constructor(
    private userService: UserService,
    private authService: AuthService,
  ) {}

  @Post('login')
  @HttpCode(HttpStatus.OK)
  @ApiOkResponse({
    type: LoginPayloadDto,
    description: 'User info with access token',
  })
  async userLogin(
    @Body() userLoginDto: UserLoginDto,
  ): Promise<LoginPayloadDto> {
    const userEntity = await this.authService.validateUser(userLoginDto);

    const token = await this.authService.createAccessToken({
      userId: userEntity.id,
      role: userEntity.role,
    });

    return LoginPayloadDto.create({
      user: userEntity.toDto(),
      accessToken: token,
    });
  }

  @Post('register')
  @HttpCode(HttpStatus.OK)
  @ApiOkResponse({ type: UserDto, description: 'Successfully Registered' })
  @ApiFile({ name: 'avatar' })
  async userRegister(
    @Body() userRegisterDto: UserRegisterDto,
    @UploadedFile() file?: Reference<IFile>,
  ): Promise<UserDto> {
    const createdUser = await this.userService.createUser(
      userRegisterDto,
      file,
    );

    return createdUser.toDto({
      isActive: true,
    });
  }

  @Version('1')
  @Get('me')
  @HttpCode(HttpStatus.OK)
  @Auth([RoleType.USER, RoleType.ADMIN])
  @ApiOkResponse({ type: UserDto, description: 'current user info' })
  getCurrentUser(@AuthUser() user: UserEntity): UserDto {
    return user.toDto();
  }
}

import { registerAs } from '@nestjs/config';
import {
  IsOptional,
  IsInt,
  Min,
  Max,
  IsString,
  ValidateIf,
  IsBoolean,
} from 'class-validator';

import validateConfig from '@src/utils/validate-config';

import { DatabaseConfig } from './database-config.type';

class EnvironmentVariablesValidator {
  @ValidateIf((envValues) => envValues.DATABASE_URL)
  @IsString()
  DATABASE_URL: string;

  @ValidateIf((envValues) => !envValues.DATABASE_URL)
  @IsString()
  DATABASE_TYPE: string;

  @ValidateIf((envValues) => !envValues.DATABASE_URL)
  @IsString()
  DATABASE_HOST: string;

  @ValidateIf((envValues) => !envValues.DATABASE_URL)
  @IsInt()
  @Min(0)
  @Max(65535)
  DATABASE_PORT: number;

  @ValidateIf((envValues) => !envValues.DATABASE_URL)
  @IsString()
  DATABASE_PASSWORD: string;

  @ValidateIf((envValues) => !envValues.DATABASE_URL)
  @IsString()
  DATABASE_NAME: string;

  @ValidateIf((envValues) => !envValues.DATABASE_URL)
  @IsString()
  DATABASE_USERNAME: string;

  @IsBoolean()
  @IsOptional()
  DATABASE_SYNCHRONIZE: boolean;

  @IsInt()
  @IsOptional()
  DATABASE_MAX_CONNECTIONS: number;

  @IsBoolean()
  @IsOptional()
  DATABASE_SSL_ENABLED: boolean;

  @IsBoolean()
  @IsOptional()
  DATABASE_REJECT_UNAUTHORIZED: boolean;

  @IsString()
  @IsOptional()
  DATABASE_CA: string;

  @IsString()
  @IsOptional()
  DATABASE_KEY: string;

  @IsString()
  @IsOptional()
  DATABASE_CERT: string;
}

export default registerAs<DatabaseConfig>('database', () => {
  validateConfig(process.env, EnvironmentVariablesValidator);

  return {
    isDocumentDatabase: ['mongodb'].includes(process.env.DATABASE_TYPE ?? ''),
    url: process.env.DATABASE_URL,
    type: process.env.DATABASE_TYPE,
    host: process.env.DATABASE_HOST,
    port: process.env.DATABASE_PORT
      ? parseInt(process.env.DATABASE_PORT, 10)
      : 5432,
    password: process.env.DATABASE_PASSWORD,
    name: process.env.DATABASE_NAME,
    username: process.env.DATABASE_USERNAME,
    synchronize: process.env.DATABASE_SYNCHRONIZE === 'true',
    maxConnections: process.env.DATABASE_MAX_CONNECTIONS
      ? parseInt(process.env.DATABASE_MAX_CONNECTIONS, 10)
      : 100,
    sslEnabled: process.env.DATABASE_SSL_ENABLED === 'true',
    rejectUnauthorized: process.env.DATABASE_REJECT_UNAUTHORIZED === 'true',
    ca: process.env.DATABASE_CA,
    key: process.env.DATABASE_KEY,
    cert: process.env.DATABASE_CERT,
  };
});

