import { Repository, SelectQueryBuilder } from 'typeorm';
import { User } from '@/user/entities/user.entity';
import { InjectRepository } from '@nestjs/typeorm';
import { Injectable } from '@nestjs/common';

export interface IUserRepository {
  createUser(user: User): Promise<User>;

  updateUser(user: User): Promise<void>;

  findUsers(
    page: number,
    pageSize: number,
    orderBy: string,
    order: 'ASC' | 'DESC',
    searchTerm?: string
  ): Promise<[User[], number]>;

  findUserByName(name: string): Promise<User>;

  findUserByEmail(email: string): Promise<User>;

  findUserById(id: number): Promise<User>;

  getAllUsers(): Promise<User[]>;

  removeUser(user: User): Promise<User>;
}

@Injectable()
export class UserRepository implements IUserRepository {
  constructor(
    @InjectRepository(User)
    private readonly userRepository: Repository<User>
  ) {}

  async createUser(user: User): Promise<User> {
    return await this.userRepository.save(user);
  }

  async updateUser(user: User): Promise<void> {
    await this.userRepository.update(user.id, user);
  }

  async findUsers(
    page: number,
    pageSize: number,
    orderBy: string,
    order: 'ASC' | 'DESC',
    searchTerm?: string
  ): Promise<[User[], number]> {
    const skip = (page - 1) * pageSize;
    const take = pageSize;

    const queryBuilder: SelectQueryBuilder<User> = this.userRepository
      .createQueryBuilder('user')
      .orderBy(`user.${orderBy}`, order)
      .skip(skip)
      .take(take);

    // Apply filter criteria to the query
    if (searchTerm) {
      queryBuilder.andWhere('user.name LIKE :name', { name: `%${searchTerm}%` });
    }

    return await queryBuilder.getManyAndCount();
  }

  async findUserByEmail(email: string): Promise<User> {
    return await this.userRepository.findOneBy({
      email: email
    });
  }

  async findUserById(id: number): Promise<User> {
    return await this.userRepository.findOneBy({
      id: id
    });
  }

  async findUserByName(name: string): Promise<User> {
    return await this.userRepository.findOneBy({
      name: name
    });
  }

  async removeUser(user: User): Promise<User> {
    return await this.userRepository.remove(user);
  }

  async getAllUsers(): Promise<User[]> {
    return await this.userRepository.find();
  }
}

import { Injectable } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { TaskLogEntity } from '../entities/task-log.entity';
import { LessThan, Like, Repository } from 'typeorm';
import { TaskLogQueryDto } from '../dto/log.dto';
import { paginate } from '~/helper/pagination';
import { isNil } from 'lodash';

@Injectable()
export class TaskLogService {
  constructor(
    @InjectRepository(TaskLogEntity)
    private readonly taskLogRepository: Repository<TaskLogEntity>,
  ) {}

  async create(
    tid: number,
    status: number,
    time?: number,
    err?: string,
  ): Promise<number> {
    const taskLog = await this.taskLogRepository.save({
      status,
      consumeTime: time,
      detail: err,
      task: {
        id: tid,
      },
    });

    return taskLog.id;
  }

  async list({ currentPage, pageSize, name, status }: TaskLogQueryDto) {
    const queryBuilder = await this.taskLogRepository
      .createQueryBuilder('task_log')
      .leftJoinAndSelect('task_log.task', 'task')
      .where({
        ...(name && {
          task: {
            name: Like(`%${name}%`),
          },
        }),
        ...(!isNil(status) && { status }),
      })
      .orderBy({ 'task_log.createdAt': 'DESC' });

    const { list, total } = await paginate<TaskLogEntity>(queryBuilder, {
      currentPage,
      pageSize,
    });

    const listDate = list.map((item) => {
      return {
        ...item,
        taskId: item.task.id,
        name: item.task.name,
      };
    });

    return {
      currentPage,
      pageSize,
      list: listDate,
      total,
    };
  }

  async deleteLogs(ids: number[]): Promise<void> {
    await this.taskLogRepository.delete(ids);
  }

  async clearLog() {
    await this.taskLogRepository.clear();
  }

  async clearLogBeforeTime(time: Date) {
    await this.taskLogRepository.delete({
      createdAt: LessThan(time),
    });
  }
}

import { SetMetadata } from '@nestjs/common';

import { GoogleCloudPubsubMessage, PubsubTopicConfiguration } from './client';
import {
  GOOGLE_CLOUD_PUBSUB_BATCH_SUBSCRIBE,
  GOOGLE_CLOUD_PUBSUB_SUBSCRIBE,
} from './google-cloud-pubsub.constants';

export interface PubsubSubscribeMetadata {
  subscription: string;
  topic: string;
}

export interface PubsubBatchSubscribeMetadata {
  subscription: string;
  topic: string;
}

export function createSubscribeDecorator<
  Topics extends readonly PubsubTopicConfiguration[],
  PayloadMap extends Record<string, unknown>,
>() {
  type SubscriptionNamePerTopicName<TopicName extends keyof PayloadMap> =
    Extract<
      Topics[number],
      { name: TopicName }
    >['subscriptions'][number]['name'];

  return <TopicName extends keyof PayloadMap & string>(
    topic: TopicName,
    subscription: SubscriptionNamePerTopicName<TopicName>,
  ) => {
    return (
      target: object,
      key: string | symbol,
      descriptor: TypedPropertyDescriptor<
        (
          payload: GoogleCloudPubsubMessage<PayloadMap[TopicName]>,
        ) => Promise<void>
      >,
    ) => {
      SetMetadata(GOOGLE_CLOUD_PUBSUB_SUBSCRIBE, {
        subscription,
        topic,
      } as PubsubSubscribeMetadata)(target, key, descriptor);

      return descriptor;
    };
  };
}

export function createBatchSubscribeDecorator<
  Topics extends readonly PubsubTopicConfiguration[],
  PayloadMap extends Record<string, unknown>,
>() {
  type SubscriptionNamePerTopicName<TopicName extends keyof PayloadMap> =
    Extract<
      Topics[number],
      { name: TopicName }
    >['subscriptions'][number]['name'];

  return <TopicName extends keyof PayloadMap & string>(
    topic: TopicName,
    subscription: SubscriptionNamePerTopicName<TopicName>,
  ) => {
    return (
      target: object,
      key: string | symbol,
      descriptor: TypedPropertyDescriptor<
        (
          payload: GoogleCloudPubsubMessage<PayloadMap[TopicName]>[],
        ) => Promise<void>
      >,
    ) => {
      SetMetadata(GOOGLE_CLOUD_PUBSUB_BATCH_SUBSCRIBE, {
        subscription,
        topic,
      } as PubsubBatchSubscribeMetadata)(target, key, descriptor);

      return descriptor;
    };
  };
}

import fs from "fs";
import path from "path";

import { CommandExecutor } from "./CommandExecutor";
import { FileRetriever } from "./FileRetriever";

export class PackageManager {
  public manager: Manager = "npm";
  public get file(): string {
    return path.join(this.directory, "package.json");
  }

  public static async mount(): Promise<PackageManager> {
    const location: string | null = await FileRetriever.directory(
      "package.json",
    )(process.cwd());
    if (location === null)
      throw new Error(`Unable to find "package.json" file`);

    return new PackageManager(
      location,
      await this.load(path.join(location, "package.json")),
    );
  }

  public async save(modifier: (data: Package.Data) => void): Promise<void> {
    const content: string = await fs.promises.readFile(this.file, "utf8");
    this.data = JSON.parse(content);
    modifier(this.data);

    return fs.promises.writeFile(
      this.file,
      JSON.stringify(this.data, null, 2),
      "utf8",
    );
  }

  public install(props: {
    dev: boolean;
    modulo: string;
    version?:
      | `latest`
      | `next`
      | `^${number}.${number}.${number}`
      | (string & {});
    force?: boolean;
  }): boolean {
    const middle: string = [
      installCmdTable[this.manager],
      props.dev ? devOptionTable[this.manager] : "",
    ]
      .filter((str) => !!str.length)
      .join(" ");
    const modulo: string = `${props.modulo}${props.version ? `@${props.version}` : ""}`;
    CommandExecutor.run([this.manager, middle, modulo].join(" "));
    return true;
  }

  private constructor(
    public readonly directory: string,
    public data: Package.Data,
  ) {}

  private static async load(file: string): Promise<Package.Data> {
    const content: string = await fs.promises.readFile(file, "utf8");
    return JSON.parse(content);
  }
}
export namespace Package {
