import { HttpError } from "./HttpError";

export namespace NestiaSimulator {
  export interface IProps {
    host: string;
    path: string;
    method: "GET" | "POST" | "PATCH" | "PUT" | "DELETE";
    contentType: string;
  }

  export const assert = (props: IProps) => {
    return {
      param: param(props),
      query: query(props),
      body: body(props),
    };
  };
  const param =
    (props: IProps) =>
    (name: string) =>
    <T>(task: () => T): void => {
      validate((exp) => `URL parameter "${name}" is not ${exp.expected} type.`)(
        props,
      )(task);
    };

  const query =
    (props: IProps) =>
    <T>(task: () => T): void =>
      validate(
        () => "Request query parameters are not following the promised type.",
      )(props)(task);

  const body =
    (props: IProps) =>
    <T>(task: () => T): void =>
      validate(() => "Request body is not following the promised type.")(props)(
        task,
      );

  const validate =
    (message: (exp: TypeGuardError) => string, path?: string) =>
    (props: IProps) =>
    <T>(task: () => T): void => {
      try {
        task();
      } catch (exp) {
        if (isTypeGuardError(exp))
          throw new HttpError(
            props.method,
            props.host + props.path,
            400,
            {
              "Content-Type": props.contentType,
            },
            JSON.stringify({
              method: exp.method,
              path: path ?? exp.path,
              expected: exp.expected,
              value: exp.value,
              message: message(exp),
            }),
          );
        throw exp;
      }
    };
}

const isTypeGuardError = (input: any): input is TypeGuardError =>
  "string" === typeof input.method &&
  (undefined === input.path || "string" === typeof input.path) &&
  "string" === typeof input.expected &&
  "string" === typeof input.name &&
  "string" === typeof input.message &&
  (undefined === input.stack || "string" === typeof input.stack);

interface TypeGuardError extends Error {
  method: string;
  path: string | undefined;
  expected: string;
  value: any;
}

import { get, isObject, orderBy } from 'lodash';
import { GenericFunction } from '../constants';

export class Collection<T = any> {
  public raw: Array<any>;
  public size: number;

  constructor(data?: Array<any>) {
    this.raw = data || [];
    this.size = this.raw.length;
  }

  static make<T>(data?: Array<any>): Collection<T> {
    return new Collection<T>(data);
  }

  first(): T {
    return this.raw[0];
  }

  last(): T {
    return this.raw[this.size - 1];
  }

  isNotEmpty(): boolean {
    return this.size > 0;
  }

  isEmpty(): boolean {
    return this.size == 0;
  }

  remove<T>(elem: T): Collection<T> {
    return new Collection(this.raw.filter((e) => e !== elem));
  }

  pluck(key: string): Collection<T> {
    const values = [];
    if (isObject(this.raw[0])) {
      this.raw.forEach((el) => values.push(get(el, key)));
    }

    return new Collection(values);
  }

  join(delimitter: string): string {
    return this.raw.join(delimitter);
  }

  groupBy(key: string): Record<string, any> {
    const obj = {};
    for (const el of this.raw) {
      const value = get(el, key);
      if (!obj[value]) obj[value] = [];
      obj[value].push(el);
    }

    return obj;
  }

  push(elem: any): this {
    this.raw.push(elem);
    this.size = this.raw.length;
    return this;
  }

  merge(elems: any[]): this {
    this.raw = this.raw.concat(elems);
    this.size = this.raw.length;
    return this;
  }

  where(condition: Record<string, any>): Collection<T> {
    let filteredArray = this.raw;
    for (const key in condition) {
      filteredArray = filteredArray.filter((o) => {
        return get(o, key) === condition[key];
      });
    }
    return new Collection(filteredArray);
  }

  each(cb: GenericFunction): void {
    for (const i in this.raw) {
      cb(this.raw[i], i);
    }
  }

  sortByDesc<T>(arr: T[], key: string): T[] {
    return orderBy(arr, [key], ['desc']);
  }

  sortBy<T>(arr: T[], key: string): T[] {
    return orderBy(arr, [key], ['asc']);
  }
}

import {
  BadRequestException,
  ConflictException,
  ForbiddenException,
  HttpStatus,
  InternalServerErrorException,
  NotFoundException,
  UnauthorizedException,
  UnprocessableEntityException,
} from '@nestjs/common';

export const NOT_FOUND = (
  entityName: string,
  attributes: Record<string, string | number>,
  stack?: Error,
) => {
  const errors = Object.entries(attributes).reduce((acc, [key, value]) => {
    acc[key] = `${entityName} not found for ${key}: ${value}`;
    return acc;
  }, {});
  return new NotFoundException({
    statusCode: HttpStatus.NOT_FOUND,
    errors,
    stack: stack || 'No stack trace available',
  });
};

export const BAD_REQUEST = (message: string, stack?: Error) =>
  new BadRequestException({
    message,
    stack: stack || 'No stack trace available',
  });

export const INTERNAL_SERVER = (message: string, stack?: Error) =>
  new InternalServerErrorException({
    message,
    stack,
  });

export const UNPROCESSABLE_ENTITY = (
  message: string,
  attribute: string,
  stack?: Error,
) => {
  return new UnprocessableEntityException({
    statusCode: HttpStatus.UNPROCESSABLE_ENTITY,
    errors: {
      [attribute]: message,
    },
    stack: stack || 'No stack trace available',
  });
};

export const UNAUTHORIZED = (
  message: string,
  attribute: string,
  stack?: Error,
) => {
  return new UnauthorizedException({
    statusCode: HttpStatus.UNAUTHORIZED,
    errors: {
      [attribute]: message,
    },
    stack: stack || 'No stack trace available',
  });
};

export const FORBIDDEN = (
  message: string,
  attribute: string,
  stack?: Error,
) => {
  return new ForbiddenException({
    statusCode: HttpStatus.FORBIDDEN,
    errors: {
      [attribute]: message,
    },
    stack: stack || 'No stack trace available',
  });
};

export const CustomException = (
  message: string,
  attribute: string,
  stack?: Error,
) => {
  return new ConflictException({
    statusCode: HttpStatus.CONFLICT,
    errors: {
      [attribute]: message,
    },
    stack: stack || 'No stack trace available',
  });
};

import { execSync, spawnSync } from 'child_process';

export function treeKillSync(pid: number, signal?: string | number): void {
  if (process.platform === 'win32') {
    execSync('taskkill /pid ' + pid + ' /T /F');
    return;
  }

  const childs = getAllChilds(pid);
  childs.forEach(function (pid) {
    killPid(pid, signal);
  });

  killPid(pid, signal);
  return;
}

function getAllPid(): {
  pid: number;
  ppid: number;
}[] {
  const result = spawnSync('ps', ['-A', '-o', 'pid,ppid'], {
    encoding: 'utf-8',
    stdio: 'pipe',
  });

  if (result.error || !result.stdout) {
    return [];
  }

  const rows = result.stdout.trim().split('\n').slice(1);

  return rows
    .map(function (row) {
      const parts = row.match(/\s*(\d+)\s*(\d+)/);

      if (parts === null) {
        return null;
      }

      return {
        pid: Number(parts[1]),
        ppid: Number(parts[2]),
      };
    })
    .filter(<T>(input: null | undefined | T): input is T => {
      return input != null;
    });
}

function getAllChilds(pid: number) {
  const allpid = getAllPid();

  const ppidHash: {
    [key: number]: number[];
  } = {};

  const result: number[] = [];

  allpid.forEach(function (item) {
    ppidHash[item.ppid] = ppidHash[item.ppid] || [];
    ppidHash[item.ppid].push(item.pid);
  });

  const find = function (pid: number) {
    ppidHash[pid] = ppidHash[pid] || [];
    ppidHash[pid].forEach(function (childPid) {
      result.push(childPid);
      find(childPid);
    });
  };

  find(pid);
  return result;
}

function killPid(pid: number, signal?: string | number) {
  try {
    process.kill(pid, signal);
  } catch (err) {
    if ((err as NodeJS.ErrnoException).code !== 'ESRCH') {
      throw err;
    }
  }
}

